// Configuration
const RETENTION_DAYS = 30;
const BATCH_SIZE = 100;
const BASE_URL = $env.N8N_BASE_URL;

const cutoffDate = new Date();
cutoffDate.setDate(cutoffDate.getDate() - RETENTION_DAYS);
const cutoffISO = cutoffDate.toISOString();

let totalDeleted = 0;
let totalFailed = 0;
let totalKept = 0;
let hasMore = true;
let cursor = null;

while (hasMore) {
  // Fetch a batch of executions
  let url = `${BASE_URL}/api/v1/executions?limit=${BATCH_SIZE}&status=success`;
  if (cursor) url += `&cursor=${cursor}`;

  const listResp = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: { 'X-N8N-API-KEY': $env.N8N_API_KEY }
  });

  const executions = listResp.data || [];
  cursor = listResp.nextCursor;
  hasMore = !!cursor && executions.length === BATCH_SIZE;

  // Filter old executions
  const oldExecutions = executions.filter(ex => {
    const finishedAt = new Date(ex.stoppedAt || ex.startedAt);
    return finishedAt < cutoffDate;
  });

  totalKept += executions.length - oldExecutions.length;

  // Delete old executions
  for (const ex of oldExecutions) {
    try {
      await this.helpers.httpRequest({
        method: 'DELETE',
        url: `${BASE_URL}/api/v1/executions/${ex.id}`,
        headers: { 'X-N8N-API-KEY': $env.N8N_API_KEY }
      });
      totalDeleted++;
    } catch (err) {
      totalFailed++;
    }
  }

  // Safety: stop after processing 2000 executions per run
  if (totalDeleted + totalKept + totalFailed > 2000) break;
}

// Now handle failed executions older than retention
hasMore = true;
cursor = null;

while (hasMore) {
  let url = `${BASE_URL}/api/v1/executions?limit=${BATCH_SIZE}&status=error`;
  if (cursor) url += `&cursor=${cursor}`;

  const listResp = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: { 'X-N8N-API-KEY': $env.N8N_API_KEY }
  });

  const executions = listResp.data || [];
  cursor = listResp.nextCursor;
  hasMore = !!cursor && executions.length === BATCH_SIZE;

  const oldExecutions = executions.filter(ex => {
    const finishedAt = new Date(ex.stoppedAt || ex.startedAt);
    return finishedAt < cutoffDate;
  });

  totalKept += executions.length - oldExecutions.length;

  for (const ex of oldExecutions) {
    try {
      await this.helpers.httpRequest({
        method: 'DELETE',
        url: `${BASE_URL}/api/v1/executions/${ex.id}`,
        headers: { 'X-N8N-API-KEY': $env.N8N_API_KEY }
      });
      totalDeleted++;
    } catch (err) {
      totalFailed++;
    }
  }

  if (totalDeleted + totalKept + totalFailed > 4000) break;
}

return [{
  json: {
    totalDeleted,
    totalFailed,
    totalKept,
    retentionDays: RETENTION_DAYS,
    cutoffDate: cutoffISO,
    runAt: new Date().toISOString()
  }
}];
